AS $function$
BEGIN
    -- Only fire when status changes to 'cancelled'
    IF NEW.status = 'cancelled' AND OLD.status != 'cancelled' THEN
        -- Only if trip had a coupon discount
        IF COALESCE(NEW.coupon_discount, 0) > 0 THEN
            PERFORM reverse_coupon_on_cancel(NEW.id);
        END IF;
    END IF;
    RETURN NEW;
END;
