{"oid": "20217", "source": "CREATE OR REPLACE FUNCTION public._fn_increment_coupon_used_count()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_coupon_id UUID;
BEGIN
  -- Resolve coupon_id via user_coupons
  SELECT coupon_id INTO v_coupon_id
  FROM   user_coupons
  WHERE  id = NEW.user_coupon_id;

  IF v_coupon_id IS NOT NULL THEN
    UPDATE coupons
    SET    used_count = COALESCE(used_count, 0) + 1
    WHERE  id = v_coupon_id;
  END IF;

  RETURN NEW;
END;
