{"oid": "26288", "source": "CREATE OR REPLACE FUNCTION public.admin_assign_user_coupon(p_user_id uuid, p_coupon_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_coupon record;
BEGIN
  SELECT id, is_active, max_uses, used_count
  INTO v_coupon
  FROM public.coupons
  WHERE id = p_coupon_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'coupon not found';
  END IF;

  IF v_coupon.is_active IS NOT TRUE THEN
    RAISE EXCEPTION 'coupon inactive';
  END IF;

  IF v_coupon.max_uses IS NOT NULL AND v_coupon.used_count >= v_coupon.max_uses THEN
    RAISE EXCEPTION 'coupon max uses reached';
  END IF;

  INSERT INTO public.user_coupons (user_id, coupon_id)
  VALUES (p_user_id, p_coupon_id);

  UPDATE public.coupons
  SET used_count = used_count + 1
  WHERE id = p_coupon_id;
END;
$function$
", "language": "plpgsql", "arguments": "p_user_id uuid, p_coupon_id uuid", "truncated": false, "body_chars": 838, "is_trigger": false, "return_type": "void", "is_trigger_function": false}

{"oid": "26287", "source": "CREATE OR REPLACE FUNCTION public.admin_wallet_adjust(p_wallet_id uuid, p_wallet_type text, p_amount numeric, p_tx_type text DEFAULT 'adjustment'::text, p_description text DEFAULT NULL::text, p_admin_email text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_before numeric;
  v_after numeric;
BEGIN
  IF p_wallet_type NOT IN ('driver', 'user') THEN
    RAISE EXCEPTION 'invalid wallet type';
  END IF;

  IF p_tx_type NOT IN ('bonus', 'penalty', 'adjustment') THEN
    RAISE EXCEPTION 'invalid transaction type';
  END IF;

  IF p_amount IS NULL OR p_amount = 0 OR abs(p_amount) > 100000 THEN
    RAISE EXCEPTION 'invalid amount';
  END IF;

  IF p_wallet_type = 'driver' THEN
    SELECT balance INTO v_before
    FROM public.driver_wallets
    WHERE id = p_wallet_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'wallet not found';
    END IF;

    v_after := v_before + p_amount;

    UPDATE public.driver_wallets
    SET balance = v_after,
        updated_at = now()
    WHERE id = p_wallet_id;
  ELSE
    SELECT balance INTO v_before
    FROM public.user_wallets
    WHERE id = p_wallet_id
    FOR UPDATE;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'wallet not found';
    END IF;

    v_after := v_before + p_amount;

    UPDATE public.user_wallets
    SET balance = v_after,
        updated_at = now()
    WHERE id = p_wallet_id;
  END IF;

  INSERT INTO public.wallet_transactions (
    wallet_id,
    wallet_type,
    type,
    amount,
    balance_before,
    balance_after,
    description,
    status,
    metadata
  ) VALUES (
    p_wallet_id,
    p_wallet_type,
    p_tx_type,
    p_amount,
    v_before,
    v_after,
    p_description,
    'completed',
    jsonb_build_object('admin_email', p_admin_email)
  );
END;
$function$
", "language": "plpgsql", "arguments": "p_wallet_id uuid, p_wallet_type text, p_amount numeric, p_tx_type text DEFAULT 'adjustment'::text, p_description text DEFAULT NULL::text, p_admin_email text DEFAULT NULL::text", "truncated": false, "body_chars": 1836, "is_trigger": false, "return_type": "void", "is_trigger_function": false}

{"oid": "25221", "source": "CREATE OR REPLACE FUNCTION public.apply_coupon_to_trip(p_trip_id uuid, p_coupon_code character varying, p_user_id uuid, p_original_price numeric)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_coupon RECORD;
    v_discount numeric;
    v_user_coupon_id uuid;
    v_final_price numeric;
    v_new_spent numeric;
BEGIN
    -- Step 1: Re-validate coupon atomically
    SELECT * INTO v_coupon
    FROM validate_coupon(p_coupon_code, p_original_price, p_user_id);

    IF v_coupon IS NULL OR v_coupon.id IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'coupon_invalid_or_expired'
        );
    END IF;

    v_discount := v_coupon.discount_amount;
    v_final_price := GREATEST(p_original_price - v_discount, 0);

    -- Step 2: Upsert user_coupons ‚Üí mark as used
    INSERT INTO user_coupons (user_id, coupon_id, is_used, used_at)
    VALUES (p_user_id, v_coupon.id, true, now())
    ON CONFLICT (user_id, coupon_id)
    DO UPDATE SET is_used = true, used_at = now()
    RETURNING id INTO v_user_coupon_id;

    -- Step 3: Insert usage audit record (unique per trip)
    INSERT INTO coupon_usages (trip_id, user_coupon_id, discount_amount)
    VALUES (p_trip_id, v_user_coupon_id, v_discount)
    ON CONFLICT (trip_id) DO NOTHING;

    -- Step 4: Increment global usage counter
    UPDATE coupons
    SET used_count = used_count + 1,
        spent_budget = COALESCE(spent_budget, 0) + v_discount
    WHERE id = v_coupon.id
    RETURNING spent_budget INTO v_new_spent;

    -- Step 5: Auto-deactivate if budget exhausted
    IF (SELECT budget_limit FROM coupons WHERE id = v_coupon.id) IS NOT NULL
       AND v_new_spent >= (SELECT budget_limit FROM coupons WHERE id = v_coupon.id) THEN
        UPDATE coupons SET is_active = false WHERE id = v_coupon.id;
    END IF;

    -- Step 6: Auto-deactivate if max uses reached
    IF (SELECT max_uses FROM coupons WHERE id = v_coupon.id) IS NOT NULL
       AND (SELECT used_count FROM coupons WHERE id = v_coupon.id) >= (SELECT max_uses FROM coupons WHERE id = v_coupon.id) THEN
        UPDATE coupons SET is_active = false WHERE id = v_coupon.id;
    END IF;

    -- Step 7: Update the trip record with discount info
    UPDATE trips
    SET coupon_discount = v_discount,
        final_price     = v_final_price
    WHERE id = p_trip_id;

    RETURN jsonb_build_object(
        'success', true,
        'discount', v_discount,
        'final_price', v_final_price,
        'coupon_id', v_coupon.id
    );
END;
$function$
", "language": "plpgsql", "arguments": "p_trip_id uuid, p_coupon_code character varying, p_user_id uuid, p_original_price numeric", "truncated": false, "body_chars": 2572, "is_trigger": false, "return_type": "jsonb", "is_trigger_function": false}

{"oid": "21494", "source": "CREATE OR REPLACE FUNCTION public.approve_withdrawal(p_withdrawal_id uuid, p_admin_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_withdrawal  withdrawal_requests%ROWTYPE;
BEGIN
  IF NOT is_admin_user() THEN
    RETURN jsonb_build_object('success', false, 'error', 'admin_only');
  END IF;

  SELECT * INTO v_withdrawal
  FROM withdrawal_requests
  WHERE id = p_withdrawal_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_found');
  END IF;

  IF v_withdrawal.status != 'pending' THEN
    RETURN jsonb_build_object('success', false, 'error', 'not_pending', 'status', v_withdrawal.status);
  END IF;

  UPDATE withdrawal_requests SET
    status       = 'completed',
    admin_id     = p_admin_id,
    processed_at = now(),
    updated_at   = now()
  WHERE id = p_withdrawal_id;

  UPDATE driver_wallets SET
    pending_withdrawal = pending_withdrawal - v_withdrawal.amount,
    total_withdrawn    = total_withdrawn + v_withdrawal.amount,
    updated_at         = now()
  WHERE id = v_withdrawal.driver_id;

  UPDATE wallet_transactions SET
    status = 'completed'
  WHERE reference_id = p_withdrawal_id
    AND type = 'withdrawal';

  RETURN jsonb_build_object('success', true, 'withdrawal_id', p_withdrawal_id);
END;
$function$
", "language": "plpgsql", "arguments": "p_withdrawal_id uuid, p_admin_id uuid", "truncated": false, "body_chars": 1347, "is_trigger": false, "return_type": "jsonb", "is_trigger_function": false}

{"oid": "25394", "source": "CREATE OR REPLACE FUNCTION public.assign_driver_to_area(p_driver_id uuid, p_service_area_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF NOT public.is_admin_user() THEN
    RAISE EXCEPTION 'Unauthorized';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM users WHERE id = p_driver_id AND role = 'driver') THEN
    RAISE EXCEPTION 'Driver not found';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM service_areas WHERE id = p_service_area_id AND is_active = true) THEN
    RAISE EXCEPTION 'Area not found or inactive';
  END IF;

  INSERT INTO public.driver_service_areas (driver_id, service_area_id, assigned_by)
  VALUES (p_driver_id, p_service_area_id, auth.uid())
  ON CONFLICT (driver_id, service_area_id)
  DO UPDATE SET is_active = true, assigned_at = now(), assigned_by = auth.uid();

  PERFORM public.log_admin_action('assign_driver_area', 'driver_service_areas', p_driver_id, NULL,
    jsonb_build_object('service_area_id', p_service_area_id));

  RETURN jsonb_build_object('success', true);
END;
$function$
", "language": "plpgsql", "arguments": "p_driver_id uuid, p_service_area_id uuid", "truncated": false, "body_chars": 1038, "is_trigger": false, "return_type": "jsonb", "is_trigger_function": false}

{"oid": "25450", "source": "CREATE OR REPLACE FUNCTION public.award_daily_bonus(p_driver_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_today       date := CURRENT_DATE;
  v_rule        record;
  v_drv         record;
  v_trips       int;
  v_count       int := 0;
  v_txn_id      uuid;
  v_details     jsonb := '[]'::jsonb;
  v_lock_id     bigint;
  v_bal_before  numeric(12,2);
BEGIN

  FOR v_rule IN
    SELECT * FROM public.bonus_rules
    WHERE trigger_type = 'daily_trips'
      AND is_active = true
      AND (starts_at IS NULL OR starts_at <= now())
      AND (expires_at IS NULL OR expires_at > now())
  LOOP

    FOR v_drv IN
      SELECT dp.id AS did, dp.vehicle_type
      FROM public.drivers_profile dp
      WHERE dp.is_verified = true
        AND (p_driver_id IS NULL OR dp.id = p_driver_id)
        AND (v_rule.vehicle_types IS NULL
             OR lower(dp.vehicle_type) = ANY(v_rule.vehicle_types))
        AND (v_rule.service_area_id IS NULL
             OR EXISTS (
               SELECT 1 FROM driver_service_areas dsa
               WHERE dsa.driver_id = dp.id
                 AND dsa.service_area_id = v_rule.service_area_id
                 AND dsa.is_active = true
             ))
        AND NOT EXISTS (
          SELECT 1 FROM driver_bonus_ledger dbl
          WHERE dbl.driver_id = dp.id
            AND dbl.bonus_rule_id = v_rule.id
            AND dbl.period_key = v_today
        )
    LOOP

      -- Advisory lock per driver+rule+day
      v_lock_id := hashtext(v_drv.did::text || v_rule.id::text || v_today::text);
      IF NOT pg_try_advisory_xact_lock(v_lock_id) THEN
        CONTINUE;
      END IF;

      SELECT count(*) INTO v_trips
      FROM public.trips
      WHERE driver_id = v_drv.did
        AND status = 'completed'
        AND completed_at >= v_today::timestamptz
        AND completed_at < (v_today + 1)::timestamptz;

      IF v_trips < v_rule.threshold THEN
        CONTINUE;
      END IF;

      -- 1. Ledger entry first (idempotency gate)
      BEGIN
        INSERT INTO public.driver_bonus_ledger
          (driver_id, bonus_rule_id, period_key, bonus_amount, trips_counted)
        VALUES
          (v_drv.did, v_rule.id, v_today, v_rule.bonus_amount, v_trips);
      EXCEPTION WHEN unique_violation THEN
        CONTINUE;
      END;

      -- 2. Get current balance for balance_before
      SELECT balance INTO v_bal_before
      FROM public.driver_wallets WHERE id = v_drv.did;

      -- 3. Wallet transaction (type is enum wallet_transaction_type)
      INSERT INTO public.wallet_transactions
        (wallet_id, wallet_type, type, amount, balance_before, balance_after, status, description)
      VALUES
        (v_drv.did, 'driver', 'bonus'::wallet_transaction_type,
         v_rule.bonus_amount,
         v_bal_before,
         v_bal_before + v_rule.bonus_amount,
         'completed'::wallet_transaction_status,
         format('Daily bonus [%s]: %s trips on %s', v_rule.name, v_trips, v_today))
      RETURNING id INTO v_txn_id;

      -- 4. Credit wallet (id = driver uuid)
      UPDATE public.driver_wallets SET
        balance      = balance + v_rule.bonus_amount,
        total_earned = total_earned + v_rule.bonus_amount,
        updated_at   = now()
      WHERE id = v_drv.did;

      -- 5. Link transaction to ledger
      UPDATE public.driver_bonus_ledger
      SET transaction_id = v_txn_id
      WHERE driver_id = v_drv.did
        AND bonus_rule_id = v_rule.id
        AND period_key = v_today;

      v_count := v_count + 1;
      v_details := v_details || jsonb_build_object(
        'driver_id', v_drv.did, 'rule', v_rule.name,
        'amount', v_rule.bonus_amount, 'trips', v_trips
      );

    END LOOP;
  END LOOP;

  RETURN jsonb_build_object(
    'success', true, 'date', v_today,
    'awarded_count', v_count, 'details', v_details
  );
END;
$function$
", "language": "plpgsql", "arguments": "p_driver_id uuid DEFAULT NULL::uuid", "truncated": false, "body_chars": 3868, "is_trigger": false, "return_type": "jsonb", "is_trigger_function": false}

{"oid": "21061", "source": "CREATE OR REPLACE FUNCTION public.calculate_trip_price(p_vehicle_type character varying, p_distance_km numeric)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_base_fare NUMERIC;
    v_price_per_km NUMERIC;
    v_minimum_fare NUMERIC;
    v_total NUMERIC;
BEGIN
    -- First try vehicle_types table (primary source)
    SELECT base_fare, price_per_km
    INTO v_base_fare, v_price_per_km
    FROM vehicle_types
    WHERE name = p_vehicle_type AND is_active = true;

    -- Fallback to pricing_config if not found in vehicle_types
    IF NOT FOUND THEN
        SELECT base_fare, price_per_km, minimum_fare
        INTO v_base_fare, v_price_per_km, v_minimum_fare
        FROM pricing_config
        WHERE vehicle_type = p_vehicle_type;
    END IF;

    -- Final fallback: default pricing
    IF NOT FOUND THEN
        v_base_fare := 10;
        v_price_per_km := 7;
        v_minimum_fare := 10;
    END IF;

    -- Calculate total price
    v_total := v_base_fare + (v_price_per_km * p_distance_km);

    -- Apply minimum fare if set
    IF v_minimum_fare IS NOT NULL AND v_total < v_minimum_fare THEN
        v_total := v_minimum_fare;
    END IF;

    RETURN ROUND(v_total, 2);
END;
$function$
", "language": "plpgsql", "arguments": "p_vehicle_type character varying, p_distance_km numeric", "truncated": false, "body_chars": 1229, "is_trigger": false, "return_type": "numeric", "is_trigger_function": false}

{"oid": "25123", "source": "CREATE OR REPLACE FUNCTION public.cancel_trip(p_trip_id uuid, p_user_id uuid, p_cancelled_by text, p_cancel_reason text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  trip_record RECORD;
BEGIN
  SELECT * INTO trip_record FROM trips WHERE id = p_trip_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Trip not found';
  END IF;

  IF p_cancelled_by NOT IN ('user', 'driver', 'system') THEN
    RAISE EXCEPTION 'Invalid cancelled_by value: %', p_cancelled_by;
  END IF;

  IF trip_record.status NOT IN ('searching', 'accepted', 'in_progress') THEN
    RAISE EXCEPTION 'Cannot cancel trip with status: %', trip_record.status;
  END IF;

  IF p_cancelled_by = 'user' AND trip_record.user_id != p_user_id THEN
    RAISE EXCEPTION 'User not authorized to cancel this trip';
  END IF;

  IF p_cancelled_by = 'driver' AND trip_record.driver_id != p_user_id THEN
    RAISE EXCEPTION 'Driver not authorized to cancel this trip';
  END IF;

  IF p_cancelled_by = 'system'
     AND trip_record.user_id != p_user_id
     AND trip_record.driver_id != p_user_id THEN
    RAISE EXCEPTION 'System cancel only allowed in trip participant context';
  END IF;

  UPDATE trips
  SET status = 'cancelled',
      cancelled_by = p_cancelled_by,
      cancel_reason = p_cancel_reason,
      cancelled_at = NOW(),
      updated_at = NOW()
  WHERE id = p_trip_id;
END;
$function$
", "language": "plpgsql", "arguments": "p_trip_id uuid, p_user_id uuid, p_cancelled_by text, p_cancel_reason text DEFAULT NULL::text", "truncated": false, "body_chars": 1396, "is_trigger": false, "return_type": "void", "is_trigger_function": false}

