{"oid": "19549", "source": "CREATE OR REPLACE FUNCTION public.demote_user_from_admin(p_user_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF NOT is_admin_user() THEN
    RAISE EXCEPTION 'Only admins can demote users from admin';
  END IF;

  IF p_user_id = auth.uid() THEN
    RAISE EXCEPTION 'Cannot demote yourself from admin';
  END IF;

  UPDATE users
  SET is_admin = false
  WHERE id = p_user_id;

  PERFORM log_admin_action('DEMOTE_FROM_ADMIN', 'users', p_user_id,
    jsonb_build_object('is_admin', true),
    jsonb_build_object('is_admin', false));

  RETURN FOUND;
END;
