{"oid": "20665", "source": "CREATE OR REPLACE FUNCTION public.driver_accept_trip(p_trip_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_trip RECORD;
  v_driver_id UUID := auth.uid();
  v_has_active BOOLEAN;
BEGIN
  -- Check driver doesn't already have an active trip
  SELECT EXISTS(
    SELECT 1 FROM trips
    WHERE driver_id = v_driver_id
      AND status IN ('accepted', 'in_progress')
  ) INTO v_has_active;

  IF v_has_active THEN
    RETURN jsonb_build_object('success', false, 'error', 'ŔĄōĮŔäŔÉ ōĪō≠ŔĄō© ŔÜōīō∑ō© ō®ōßŔĄŔĀōĻŔĄ');
  END IF;

  -- Lock the trip row to prevent race condition
  SELECT * INTO v_trip
  FROM trips
  WHERE id = p_trip_id
  FOR UPDATE SKIP LOCKED;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'ōßŔĄōĪō≠ŔĄō© ōļŔäōĪ ŔÖŔąō¨ŔąōĮō© ō£Ŕą ŔÖō≠ō¨Ŕąō≤ō©');
  END IF;

  IF v_trip.status != 'searching' THEN
    RETURN jsonb_build_object('success', false, 'error', 'ōßŔĄōĪō≠ŔĄō© ŔĄŔÖ ō™ōĻōĮ ŔÖō™ōßō≠ō© (ōßŔĄō≠ōßŔĄō©: ' || v_trip.status || ')');
  END IF;

  -- Accept the trip atomically
  UPDATE trips
  SET status = 'accepted',
      driver_id = v_driver_id,
      accepted_at = NOW(),
      updated_at = NOW()
  WHERE id = p_trip_id;

  -- Update the driver's offer status
  UPDATE trip_offers
  SET status = 'accepted',
      updated_at = NOW()
  WHERE trip_id = p_trip_id
    AND driver_id = v_driver_id;

  RETURN jsonb_build_object('success', true);
END;
$function$
", "language": "plpgsql", "arguments": "p_trip_id uuid", "truncated": false, "body_chars": 1378, "is_trigger": false, "return_type": "jsonb", "is_trigger_function": false}

{"oid": "20717", "source": "CREATE OR REPLACE FUNCTION public.driver_complete_trip(p_trip_id uuid, p_driver_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_trip RECORD;
BEGIN
  SELECT * INTO v_trip
  FROM trips
  WHERE id = p_trip_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'ōßŔĄōĪō≠ŔĄō© ōļŔäōĪ ŔÖŔąō¨ŔąōĮō©');
  END IF;

  IF v_trip.driver_id != p_driver_id THEN
    RETURN jsonb_build_object('success', false, 'error', 'ō£ŔÜō™ ŔĄō≥ō™ ō≥ōßō¶Ŕā ŔáōįŔá ōßŔĄōĪō≠ŔĄō©');
  END IF;

  IF v_trip.status != 'in_progress' THEN
    RETURN jsonb_build_object('success', false, 'error', 'ŔĄōß ŔäŔÖŔÉŔÜ ō•ŔÉŔÖōßŔĄ ōĪō≠ŔĄō© ŔĀŔä ō≠ōßŔĄō©: ' || v_trip.status);
  END IF;

  UPDATE trips
  SET status = 'completed',
      completed_at = NOW(),
      updated_at = NOW()
  WHERE id = p_trip_id;

  -- Increment driver's total_trips
  UPDATE users
  SET total_trips = COALESCE(total_trips, 0) + 1,
      updated_at = NOW()
  WHERE id = p_driver_id;

  RETURN jsonb_build_object('success', true);
END;
$function$
