{"oid": "20716", "source": "CREATE OR REPLACE FUNCTION public.driver_start_trip(p_trip_id uuid, p_driver_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
