{"oid": "26135", "source": "CREATE OR REPLACE FUNCTION public.fn_add_route_stopover(p_route_plan_id uuid, p_after_seq smallint, p_lat double precision, p_lng double precision, p_address text DEFAULT NULL::text, p_wait_min numeric DEFAULT 0)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_new_seq SMALLINT;
    v_wp_id UUID;
BEGIN
    v_new_seq := p_after_seq + 1;

    -- Shift all waypoints at or after the new position
    UPDATE public.trip_route_waypoints
    SET seq_order = seq_order + 1
    WHERE route_plan_id = p_route_plan_id
      AND seq_order >= v_new_seq;

    -- Insert the stopover
    INSERT INTO public.trip_route_waypoints (
        route_plan_id, seq_order, role,
        lat, lng, address, planned_wait_min
    ) VALUES (
        p_route_plan_id, v_new_seq, 'stopover',
        p_lat, p_lng, p_address, p_wait_min
    )
    RETURNING id INTO v_wp_id;

    RETURN v_wp_id;
END;
$function$
", "language": "plpgsql", "arguments": "p_route_plan_id uuid, p_after_seq smallint, p_lat double precision, p_lng double precision, p_address text DEFAULT NULL::text, p_wait_min numeric DEFAULT 0", "truncated": false, "body_chars": 941, "is_trigger": false, "return_type": "uuid", "is_trigger_function": false}

{"oid": "25197", "source": "CREATE OR REPLACE FUNCTION public.fn_auto_reverse_coupon_on_cancel()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Only fire when status changes to 'cancelled'
    IF NEW.status = 'cancelled' AND OLD.status != 'cancelled' THEN
        -- Only if trip had a coupon discount
        IF COALESCE(NEW.coupon_discount, 0) > 0 THEN
            PERFORM reverse_coupon_on_cancel(NEW.id);
        END IF;
    END IF;
    RETURN NEW;
END;
$function$
", "language": "plpgsql", "arguments": "", "truncated": false, "body_chars": 456, "is_trigger": true, "return_type": "trigger", "is_trigger_function": true}

{"oid": "26134", "source": "CREATE OR REPLACE FUNCTION public.fn_create_route_plan_from_legacy(p_trip_id uuid, p_activate boolean DEFAULT true)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_trip RECORD;
    v_plan_id UUID;
BEGIN
    SELECT * INTO v_trip FROM public.trips WHERE id = p_trip_id;
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Trip % not found', p_trip_id;
    END IF;

    -- Create the route plan
    INSERT INTO public.trip_route_plans (
        trip_id, label, status,
        total_distance_km, estimated_price,
        is_system_generated, created_by
    ) VALUES (
        p_trip_id,
        'ōßŔĄŔÖō≥ōßōĪ ōßŔĄō£ōĶŔĄŔä',
        CASE WHEN p_activate THEN 'active'::route_plan_status ELSE 'draft'::route_plan_status END,
        v_trip.distance_km,
        v_trip.price,
        true,
        NULL
    )
    RETURNING id INTO v_plan_id;

    -- Origin waypoint
    INSERT INTO public.trip_route_waypoints (
        route_plan_id, seq_order, role, lat, lng, address
    ) VALUES (
        v_plan_id, 0, 'origin',
        v_trip.pickup_lat, v_trip.pickup_lng, v_trip.pickup_address
    );

    -- Destination waypoint
    INSERT INTO public.trip_route_waypoints (
        route_plan_id, seq_order, role, lat, lng, address,
        leg_distance_km
    ) VALUES (
        v_plan_id, 1, 'destination',
        v_trip.destination_lat, v_trip.destination_lng, v_trip.destination_address,
        v_trip.distance_km
    );

    RETURN v_plan_id;
END;
$function$
", "language": "plpgsql", "arguments": "p_trip_id uuid, p_activate boolean DEFAULT true", "truncated": false, "body_chars": 1495, "is_trigger": false, "return_type": "uuid", "is_trigger_function": false}

{"oid": "21491", "source": "CREATE OR REPLACE FUNCTION public.fn_credit_driver_earnings_on_trip_complete()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
    v_commission_rate numeric;
    v_driver_earnings numeric;
    v_platform_commission numeric;
    v_coupon_discount numeric;
    v_final_price numeric;
    v_wallet_exists boolean;
BEGIN
    -- Only fire on status change to 'completed'
    IF NEW.status = 'completed' AND OLD.status != 'completed' AND NEW.driver_id IS NOT NULL THEN

        -- Get driver's commission rate
        SELECT COALESCE(dw.commission_rate, 0.15)
        INTO v_commission_rate
        FROM driver_wallets dw
        WHERE dw.id = NEW.driver_id;

        IF v_commission_rate IS NULL THEN
            v_commission_rate := 0.15;
        END IF;

        -- ‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź
        -- CRITICAL: Calculate earnings on ORIGINAL price, not final_price
        -- The coupon discount is a platform cost, not a driver cost.
        -- ‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź
        v_driver_earnings     := ROUND(NEW.price * (1 - v_commission_rate), 2);
        v_platform_commission := ROUND(NEW.price * v_commission_rate, 2);
        v_coupon_discount     := COALESCE(NEW.coupon_discount, 0);
        v_final_price         := COALESCE(NEW.final_price, NEW.price);

        -- Update trip with calculated earnings
        NEW.driver_earnings     := v_driver_earnings;
        NEW.platform_commission := v_platform_commission;

        -- Set final_price if not already set
        IF NEW.final_price IS NULL OR NEW.final_price = 0 THEN
            NEW.final_price := GREATEST(NEW.price - v_coupon_discount, 0);
            v_final_price := NEW.final_price;
        END IF;

        -- Ensure driver wallet exists
        SELECT EXISTS(
            SELECT 1 FROM driver_wallets WHERE id = NEW.driver_id
        ) INTO v_wallet_exists;

        IF NOT v_wallet_exists THEN
            INSERT INTO driver_wallets (id, balance, total_earned, total_withdrawn, pending_withdrawal, commission_rate)
            VALUES (NEW.driver_id, 0, 0, 0, 0, v_commission_rate);
        END IF;

        -- Credit driver wallet with their earnings
        UPDATE driver_wallets
        SET balance      = balance + v_driver_earnings,
            total_earned = total_earned + v_driver_earnings,
            updated_at   = now()
        WHERE id = NEW.driver_id;

        -- Record the trip_earning transaction
        INSERT INTO wallet_transactions (
            wallet_id, wallet_type, type, amount,
            balance_before, balance_after,
            reference_id, reference_type, status, description
        )
        SELECT
            NEW.driver_id,
            'driver',
            'trip_earning',
            v_driver_earnings,
            dw.balance - v_driver_earnings,
            dw.balance,
            NEW.id,
            'trip',
            'completed',
            CASE 
                WHEN v_coupon_discount > 0 THEN
                    'ō£ōĪō®ōßō≠ ōĪō≠ŔĄō© (ō≥ōĻōĪ ō£ōĶŔĄŔä ' || NEW.price || ' - ŔÉŔąō®ŔąŔÜ ' || v_coupon_discount || ')'
                ELSE
                    'ō£ōĪō®ōßō≠ ōĪō≠ŔĄō©'
            END
        FROM driver_wallets dw
        WHERE dw.id = NEW.driver_id;

        -- ‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź
        -- COUPON SUBSIDY: If coupon was used, record platform subsidy
        -- This is a ledger entry showing the platform covered the discount
        -- ‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź‚ēź
        IF v_coupon_discount > 0 THEN
            INSERT INTO wallet_transactions (
                wallet_id, wallet_type, type, amount,
                balance_before, balance_after,
                reference_id, reference_type, status, description
            )
            VALUES (
                NEW.driver_id,
                'driver',
                'coupon_subsidy',
                v_coupon_discount,
                0, -- ledger entry, not balance-affecting (driver already got full earnings)
                0,
                NEW.id,
                'trip',
                'completed',
                'ō™ōĻŔąŔäō∂ ŔÉŔąō®ŔąŔÜ - ōßŔĄŔÖŔÜōĶō© ō™ō≠ŔÖŔĄō™ ōģōĶŔÖ ' || v_coupon_discount || ' ō¨.ŔÖ'
            );
        END IF;

    END IF;

    RETURN NEW;
END;
$function$
", "language": "plpgsql", "arguments": "", "truncated": false, "body_chars": 4309, "is_trigger": true, "return_type": "trigger", "is_trigger_function": true}

{"oid": "26136", "source": "CREATE OR REPLACE FUNCTION public.fn_remove_route_stopover(p_waypoint_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_plan_id UUID;
    v_seq SMALLINT;
    v_role route_waypoint_role;
BEGIN
    SELECT route_plan_id, seq_order, role
    INTO v_plan_id, v_seq, v_role
    FROM public.trip_route_waypoints
    WHERE id = p_waypoint_id;

    IF NOT FOUND THEN RETURN false; END IF;

    -- Only stopovers can be removed via this function
    IF v_role != 'stopover' THEN
        RAISE EXCEPTION 'Cannot remove % waypoint; only stopovers allowed', v_role;
    END IF;

    DELETE FROM public.trip_route_waypoints WHERE id = p_waypoint_id;

    -- Re-sequence
    UPDATE public.trip_route_waypoints
    SET seq_order = seq_order - 1
    WHERE route_plan_id = v_plan_id
      AND seq_order > v_seq;

    RETURN true;
END;
$function$
", "language": "plpgsql", "arguments": "p_waypoint_id uuid", "truncated": false, "body_chars": 897, "is_trigger": false, "return_type": "boolean", "is_trigger_function": false}

{"oid": "25390", "source": "CREATE OR REPLACE FUNCTION public.fn_set_trip_service_area()
