", "language": "plpgsql", "arguments": "", "truncated": false, "body_chars": 371, "is_trigger": true, "return_type": "trigger", "is_trigger_function": true}

{"oid": "20719", "source": "CREATE OR REPLACE FUNCTION public.get_driver_avg_rating(p_driver_id uuid)
 RETURNS double precision
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_avg DOUBLE PRECISION;
BEGIN
  SELECT COALESCE(AVG(rating), 0) INTO v_avg
  FROM ratings
  WHERE driver_id = p_driver_id;

  RETURN ROUND(v_avg::NUMERIC, 2);
