$function$
", "language": "plpgsql", "arguments": "p_driver_id uuid", "truncated": false, "body_chars": 335, "is_trigger": false, "return_type": "double precision", "is_trigger_function": false}

{"oid": "21740", "source": "CREATE OR REPLACE FUNCTION public.get_driver_earnings_detailed(p_driver_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(driver_id uuid, completed_trips bigint, total_earnings numeric, avg_price numeric, earnings_7d numeric, earnings_30d numeric)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
DECLARE
  v_caller_id  UUID    := auth.uid();
  v_is_admin   BOOLEAN := is_admin_user();
  v_is_driver  BOOLEAN;
BEGIN
  IF v_caller_id IS NULL THEN
    RAISE EXCEPTION 'Unauthorized' USING ERRCODE = '42501';
  END IF;

  SELECT EXISTS(
    SELECT 1 FROM drivers_profile WHERE id = v_caller_id
  ) INTO v_is_driver;

  IF NOT v_is_admin AND NOT v_is_driver THEN
    RAISE EXCEPTION 'Forbidden' USING ERRCODE = '42501';
  END IF;

  IF NOT v_is_admin AND p_driver_id IS NOT NULL
                    AND p_driver_id != v_caller_id THEN
    RAISE EXCEPTION 'Forbidden: Cannot access another driver data'
      USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
  SELECT
    t.driver_id,
    COUNT(*) FILTER (
      WHERE t.status = 'completed'
    )::BIGINT                                                AS completed_trips,
    COALESCE(SUM(t.price) FILTER (
      WHERE t.status = 'completed'
    ), 0::NUMERIC)                                           AS total_earnings,
    COALESCE(AVG(t.price) FILTER (
      WHERE t.status = 'completed'
    ), 0::NUMERIC)                                           AS avg_price,
    COALESCE(SUM(t.price) FILTER (
      WHERE t.status = 'completed'
        AND t.created_at >= NOW() - INTERVAL '7 days'
    ), 0::NUMERIC)                                           AS earnings_7d,
    COALESCE(SUM(t.price) FILTER (
      WHERE t.status = 'completed'
        AND t.created_at >= NOW() - INTERVAL '30 days'
    ), 0::NUMERIC)                                           AS earnings_30d

  FROM trips t

  WHERE
    t.driver_id IS NOT NULL
    AND (
      (v_is_admin = TRUE AND (p_driver_id IS NULL OR t.driver_id = p_driver_id))
      OR
      (v_is_admin = FALSE AND v_is_driver = TRUE AND t.driver_id = v_caller_id)
    )

  GROUP BY t.driver_id;

END;
$function$
", "language": "plpgsql", "arguments": "p_driver_id uuid DEFAULT NULL::uuid", "truncated": false, "body_chars": 2136, "is_trigger": false, "return_type": "TABLE(driver_id uuid, completed_trips bigint, total_earnings numeric, avg_price numeric, earnings_7d numeric, earnings_30d numeric)", "is_trigger_function": false}

{"oid": "25453", "source": "CREATE OR REPLACE FUNCTION public.get_my_bonus_progress()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
DECLARE
  v_uid     uuid := auth.uid();
  v_today   date := CURRENT_DATE;
  v_trips   int;
  v_result  jsonb := '[]'::jsonb;
  v_rule    record;
  v_vtype   text;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM users WHERE id = v_uid AND role = 'driver') THEN
    RETURN jsonb_build_object('error', 'not_a_driver');
  END IF;

  SELECT lower(vehicle_type) INTO v_vtype FROM drivers_profile WHERE id = v_uid;

  SELECT count(*) INTO v_trips
  FROM trips
  WHERE driver_id = v_uid AND status = 'completed'
    AND completed_at >= v_today::timestamptz
    AND completed_at < (v_today + 1)::timestamptz;

  FOR v_rule IN
    SELECT br.*, dbl.awarded_at IS NOT NULL AS already_awarded
    FROM bonus_rules br
    LEFT JOIN driver_bonus_ledger dbl
      ON dbl.bonus_rule_id = br.id AND dbl.driver_id = v_uid AND dbl.period_key = v_today
    WHERE br.trigger_type = 'daily_trips' AND br.is_active = true
      AND (br.starts_at IS NULL OR br.starts_at <= now())
      AND (br.expires_at IS NULL OR br.expires_at > now())
      AND (br.vehicle_types IS NULL OR v_vtype = ANY(br.vehicle_types))
    ORDER BY br.threshold ASC
  LOOP
    v_result := v_result || jsonb_build_object(
      'rule_id', v_rule.id, 'name', v_rule.name, 'name_ar', v_rule.name_ar,
      'threshold', v_rule.threshold, 'bonus_amount', v_rule.bonus_amount,
      'trips_completed', v_trips,
      'progress_pct', LEAST(100, round((v_trips::numeric / v_rule.threshold) * 100)),
      'already_awarded', COALESCE(v_rule.already_awarded, false)
    );
  END LOOP;

  RETURN jsonb_build_object('date', v_today, 'trips_today', v_trips, 'bonuses', v_result);
END;
$function$
", "language": "plpgsql", "arguments": "", "truncated": false, "body_chars": 1753, "is_trigger": false, "return_type": "jsonb", "is_trigger_function": false}

{"oid": "26229", "source": "CREATE OR REPLACE FUNCTION public.matches_driver_corridor(p_driver_id uuid, p_pickup_lat double precision, p_pickup_lng double precision, p_dest_lat double precision, p_dest_lng double precision)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_driver RECORD;
  v_pickup_match BOOLEAN;
  v_dest_match BOOLEAN;
BEGIN
  -- Get active target route
  SELECT * INTO v_driver 
  FROM drivers_profile 
  WHERE id = p_driver_id AND target_route_active = true;

  IF NOT FOUND THEN
    RETURN TRUE; -- No target route set, meaning driver accepts all requests
  END IF;

  -- Check Origin Match using PostGIS
  IF v_driver.target_origin_lat IS NOT NULL AND v_driver.target_origin_lng IS NOT NULL THEN
     v_pickup_match := ST_DistanceSphere(
        ST_SetSRID(ST_MakePoint(p_pickup_lng, p_pickup_lat), 4326),
        ST_SetSRID(ST_MakePoint(v_driver.target_origin_lng, v_driver.target_origin_lat), 4326)
     ) <= (COALESCE(v_driver.target_origin_radius_km, 2.0) * 1000);
  ELSE
     v_pickup_match := TRUE;
  END IF;

  -- Check Destination Match using PostGIS
  IF v_driver.target_route_lat IS NOT NULL AND v_driver.target_route_lng IS NOT NULL THEN
     v_dest_match := ST_DistanceSphere(
        ST_SetSRID(ST_MakePoint(p_dest_lng, p_dest_lat), 4326),
        ST_SetSRID(ST_MakePoint(v_driver.target_route_lng, v_driver.target_route_lat), 4326)
     ) <= (COALESCE(v_driver.target_route_radius_km, 3.0) * 1000);
  ELSE
     v_dest_match := TRUE;
  END IF;

  RETURN v_pickup_match AND v_dest_match;
END;
$function$
", "language": "plpgsql", "arguments": "p_driver_id uuid, p_pickup_lat double precision, p_pickup_lng double precision, p_dest_lat double precision, p_dest_lng double precision", "truncated": false, "body_chars": 1545, "is_trigger": false, "return_type": "boolean", "is_trigger_function": false}

