{"oid": "21495", "source": "CREATE OR REPLACE FUNCTION public.reject_withdrawal(p_withdrawal_id uuid, p_admin_id uuid, p_rejection_reason text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_withdrawal withdrawal_requests%ROWTYPE;
  v_balance_before NUMERIC;
  v_balance_after  NUMERIC;
BEGIN
  IF NOT is_admin_user() THEN
    RETURN jsonb_build_object('success', false, 'error', 'admin_only');
  END IF;

  SELECT * INTO v_withdrawal
  FROM withdrawal_requests
  WHERE id = p_withdrawal_id
  FOR UPDATE;

  IF NOT FOUND OR v_withdrawal.status != 'pending' THEN
    RETURN jsonb_build_object('success', false, 'error', 'invalid_state');
  END IF;

  UPDATE withdrawal_requests SET
    status           = 'rejected',
    admin_id         = p_admin_id,
    rejection_reason = p_rejection_reason,
    processed_at     = now(),
    updated_at       = now()
  WHERE id = p_withdrawal_id;

  SELECT balance INTO v_balance_before FROM driver_wallets WHERE id = v_withdrawal.driver_id;
  v_balance_after := v_balance_before + v_withdrawal.amount;

  UPDATE driver_wallets SET
    balance            = balance + v_withdrawal.amount,
    pending_withdrawal = pending_withdrawal - v_withdrawal.amount,
    updated_at         = now()
  WHERE id = v_withdrawal.driver_id;

  UPDATE wallet_transactions SET
    status = 'reversed'
  WHERE reference_id = p_withdrawal_id AND type = 'withdrawal';

  INSERT INTO wallet_transactions (
    wallet_id, wallet_type, type, amount,
    balance_before, balance_after,
    reference_id, reference_type,
    status, description
  ) VALUES (
    v_withdrawal.driver_id, 'driver', 'withdrawal_refund', v_withdrawal.amount,
    v_balance_before, v_balance_after,
    p_withdrawal_id, 'withdrawal',
    'completed',
    'ō•ōĻōßōĮō© ō≥ō≠ō® ŔÖōĪŔĀŔąō∂: ' || p_rejection_reason
  );

  RETURN jsonb_build_object('success', true, 'refunded_amount', v_withdrawal.amount);
END;
$function$
", "language": "plpgsql", "arguments": "p_withdrawal_id uuid, p_admin_id uuid, p_rejection_reason text", "truncated": false, "body_chars": 1922, "is_trigger": false, "return_type": "jsonb", "is_trigger_function": false}

