{"oid": "21493", "source": "CREATE OR REPLACE FUNCTION public.request_driver_withdrawal(p_driver_id uuid, p_amount numeric, p_payment_method text, p_account_details jsonb, p_idempotency_key uuid DEFAULT gen_random_uuid())
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_available_balance  NUMERIC;
  v_pending_amount     NUMERIC;
  v_withdrawal_id      UUID;
  v_existing           UUID;
BEGIN
  IF auth.uid() != p_driver_id THEN
    RETURN jsonb_build_object('success', false, 'error', 'unauthorized');
  END IF;

  SELECT id INTO v_existing
  FROM withdrawal_requests
  WHERE idempotency_key = p_idempotency_key;

  IF FOUND THEN
    RETURN jsonb_build_object(
      'success', true,
      'withdrawal_id', v_existing,
      'idempotent', true
    );
  END IF;

  SELECT balance, pending_withdrawal
  INTO v_available_balance, v_pending_amount
  FROM driver_wallets
  WHERE id = p_driver_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'wallet_not_found');
  END IF;

  IF p_amount < 50 THEN
    RETURN jsonb_build_object('success', false, 'error', 'below_minimum', 'minimum', 50);
  END IF;

  IF v_available_balance < p_amount THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'insufficient_balance',
      'available', v_available_balance,
      'requested', p_amount
    );
  END IF;

  IF EXISTS (
    SELECT 1 FROM withdrawal_requests
    WHERE driver_id = p_driver_id
      AND status = 'pending'
  ) THEN
    RETURN jsonb_build_object('success', false, 'error', 'pending_withdrawal_exists');
  END IF;

  INSERT INTO withdrawal_requests (
    driver_id, amount, payment_method,
    account_details, idempotency_key, status
  ) VALUES (
    p_driver_id, p_amount, p_payment_method::withdrawal_method,
    p_account_details, p_idempotency_key, 'pending'
  )
  RETURNING id INTO v_withdrawal_id;

  UPDATE driver_wallets SET
    balance             = balance - p_amount,
    pending_withdrawal  = pending_withdrawal + p_amount,
    updated_at          = now()
  WHERE id = p_driver_id;

  INSERT INTO wallet_transactions (
    wallet_id, wallet_type, type, amount,
    balance_before, balance_after,
    reference_id, reference_type,
    status, description
  ) VALUES (
    p_driver_id, 'driver', 'withdrawal', -p_amount,
    v_available_balance, v_available_balance - p_amount,
    v_withdrawal_id, 'withdrawal',
    'pending',
    'ō∑ŔĄō® ō≥ō≠ō® ōĻō®ōĪ: ' || p_payment_method
  );

  RETURN jsonb_build_object(
    'success', true,
    'withdrawal_id', v_withdrawal_id,
    'amount', p_amount,
    'new_balance', v_available_balance - p_amount
  );
END;
$function$
", "language": "plpgsql", "arguments": "p_driver_id uuid, p_amount numeric, p_payment_method text, p_account_details jsonb, p_idempotency_key uuid DEFAULT gen_random_uuid()", "truncated": false, "body_chars": 2670, "is_trigger": false, "return_type": "jsonb", "is_trigger_function": false}

{"oid": "25389", "source": "CREATE OR REPLACE FUNCTION public.resolve_service_area(p_lat double precision, p_lng double precision)
 RETURNS uuid
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
AS $function$
DECLARE
  v_area_id uuid;
  v_point   geometry;
  v_geohash text;
BEGIN
  v_point := ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326);

  -- 1. Polygon match (precise)
  SELECT id INTO v_area_id
  FROM public.service_areas
  WHERE is_active = true AND boundary IS NOT NULL
    AND ST_Contains(boundary, v_point)
  LIMIT 1;

  IF v_area_id IS NOT NULL THEN RETURN v_area_id; END IF;

  -- 2. Geohash prefix match (fallback)
  v_geohash := ST_GeoHash(v_point, 5);
  SELECT id INTO v_area_id
  FROM public.service_areas sa
  WHERE sa.is_active = true
    AND EXISTS (
      SELECT 1 FROM unnest(sa.geohash_prefixes) pfx
      WHERE v_geohash LIKE pfx || '%'
    )
  LIMIT 1;

  RETURN v_area_id;
END;
$function$
", "language": "plpgsql", "arguments": "p_lat double precision, p_lng double precision", "truncated": false, "body_chars": 879, "is_trigger": false, "return_type": "uuid", "is_trigger_function": false}

{"oid": "21790", "source": "CREATE OR REPLACE FUNCTION public.secure_broadcast_trip_offers(p_trip_id uuid, p_search_cells text[], p_vehicle_type text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_matching_drivers UUID[];
  v_inserted_count INT := 0;
BEGIN
  -- 1. Securely find verified, available drivers in the requested cells
  SELECT array_agg(id) INTO v_matching_drivers
  FROM drivers_profile
  WHERE is_available = true
    AND is_verified = true
    AND vehicle_type ILIKE '%' || trim(p_vehicle_type) || '%'
    AND geohash5 = ANY(p_search_cells);

  IF v_matching_drivers IS NULL OR array_length(v_matching_drivers, 1) = 0 THEN
    RETURN json_build_object('success', false, 'message', 'No matching drivers found');
  END IF;

  -- 2. Securely Insert offers (bypassing client RLS) and get ONLY new drivers
  WITH inserted_offers AS (
    INSERT INTO trip_offers (trip_id, driver_id, status)
    SELECT p_trip_id, unnest(v_matching_drivers), 'pending'
    ON CONFLICT (trip_id, driver_id) DO NOTHING
    RETURNING driver_id
  )
  SELECT array_agg(driver_id) INTO v_matching_drivers FROM inserted_offers;

  IF v_matching_drivers IS NULL THEN
    v_matching_drivers := ARRAY[]::UUID[];
  END IF;

  v_inserted_count := array_length(v_matching_drivers, 1);
  IF v_inserted_count IS NULL THEN
     v_inserted_count := 0;
  END IF;

  -- Return driver IDs so the Edge Function can send them FCM pushes
  RETURN json_build_object('success', true, 'drivers_notified', v_inserted_count, 'driver_ids', v_matching_drivers);
END;
$function$
", "language": "plpgsql", "arguments": "p_trip_id uuid, p_search_cells text[], p_vehicle_type text", "truncated": false, "body_chars": 1542, "is_trigger": false, "return_type": "json", "is_trigger_function": false}

