{"oid": "20835", "source": "CREATE OR REPLACE FUNCTION public.use_coupon_atomic(p_user_id uuid, p_coupon_code text, p_trip_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  v_coupon RECORD;
  v_already_used BOOLEAN;
BEGIN
  -- Lock the coupon row
  SELECT * INTO v_coupon
  FROM coupons
  WHERE code = p_coupon_code
    AND is_active = true
    AND (expires_at IS NULL OR expires_at > NOW())
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'ōßŔĄŔÉŔąō®ŔąŔÜ ōļŔäōĪ ōĶōßŔĄō≠ ō£Ŕą ŔÖŔÜō™ŔáŔä');
  END IF;

  -- Check max uses
  IF v_coupon.max_uses IS NOT NULL THEN
    DECLARE v_current_uses INT;
    BEGIN
      SELECT COUNT(*) INTO v_current_uses
      FROM user_coupons
      WHERE coupon_id = v_coupon.id;

      IF v_current_uses >= v_coupon.max_uses THEN
        RETURN jsonb_build_object('success', false, 'error', 'ō™ŔÖ ōßō≥ō™ōģōĮōßŔÖ ōßŔĄŔÉŔąō®ŔąŔÜ ōßŔĄō≠ōĮ ōßŔĄō£ŔāōĶŔČ');
      END IF;
    END;
  END IF;

  -- Check user hasn't already used this coupon
  SELECT EXISTS(
    SELECT 1 FROM user_coupons
    WHERE user_id = p_user_id AND coupon_id = v_coupon.id
  ) INTO v_already_used;

  IF v_already_used THEN
    RETURN jsonb_build_object('success', false, 'error', 'ŔĄŔāōĮ ōßō≥ō™ōģōĮŔÖō™ Ŕáōįōß ōßŔĄŔÉŔąō®ŔąŔÜ ŔÖŔÜ Ŕāō®ŔĄ');
  END IF;

  -- Record usage atomically
  INSERT INTO user_coupons (user_id, coupon_id, trip_id, used_at)
  VALUES (p_user_id, v_coupon.id, p_trip_id, NOW());

  RETURN jsonb_build_object(
    'success', true,
    'discount_type', v_coupon.discount_type,
    'discount_value', v_coupon.discount_value
  );
END;
$function$
", "language": "plpgsql", "arguments": "p_user_id uuid, p_coupon_code text, p_trip_id uuid", "truncated": false, "body_chars": 1536, "is_trigger": false, "return_type": "jsonb", "is_trigger_function": false}

{"oid": "26207", "source": "CREATE OR REPLACE FUNCTION public.user_accept_offer(p_offer_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
    v_trip_id uuid;
    v_driver_id uuid;
    v_proposed_price numeric;
BEGIN
    -- Get offer details
    SELECT trip_id, driver_id, proposed_price 
    INTO v_trip_id, v_driver_id, v_proposed_price
    FROM trip_offers 
    WHERE id = p_offer_id AND status = 'pending';

    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'ōßŔĄōĻōĪō∂ ōļŔäōĪ ŔÖō™ōßō≠');
    END IF;

    -- Verify user owns the trip
    IF NOT EXISTS (SELECT 1 FROM trips WHERE id = v_trip_id AND user_id = auth.uid() AND status = 'searching') THEN
        RETURN jsonb_build_object('success', false, 'error', 'ōļŔäōĪ ŔÖōĶōĪō≠ ō£Ŕą ōßŔĄōĪō≠ŔĄō© ōļŔäōĪ ŔÖō™ōßō≠ō©');
    END IF;

    -- Update trip status, assigned driver, and final price
    UPDATE trips 
    SET 
        status = 'accepted', 
        driver_id = v_driver_id, 
        price = v_proposed_price,
        accepted_at = now(),
        updated_at = now()
    WHERE id = v_trip_id;

    -- Update offers status
    UPDATE trip_offers 
    SET status = 'accepted', responded_at = now(), updated_at = now()
    WHERE id = p_offer_id;

    UPDATE trip_offers 
    SET status = 'declined', responded_at = now(), updated_at = now()
    WHERE trip_id = v_trip_id AND id != p_offer_id;

    -- Update driver profile state
    UPDATE drivers_profile SET is_available = false WHERE id = v_driver_id;

    RETURN jsonb_build_object('success', true, 'trip_id', v_trip_id);
END;
$function$
", "language": "plpgsql", "arguments": "p_offer_id uuid", "truncated": false, "body_chars": 1549, "is_trigger": false, "return_type": "jsonb", "is_trigger_function": false}

{"oid": "25220", "source": "CREATE OR REPLACE FUNCTION public.validate_coupon(p_code character varying, p_trip_price numeric, p_user_id uuid)
 RETURNS TABLE(id uuid, discount_type character varying, discount_value numeric, discount_amount numeric)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_coupon RECORD;
    v_user_usage_count int;
    v_user_trip_count int;
    v_user_created_at timestamptz;
    v_discount numeric;
BEGIN
    -- 1. Find active coupon by code
    SELECT c.* INTO v_coupon
    FROM coupons c
    WHERE UPPER(c.code) = UPPER(p_code)
      AND c.is_active = true;

    IF v_coupon IS NULL THEN
        RETURN;  -- empty result = invalid
    END IF;

    -- 2. Check start date (not yet active)
    IF v_coupon.starts_at IS NOT NULL AND v_coupon.starts_at > now() THEN
        RETURN;
    END IF;

    -- 3. Check expiry
    IF v_coupon.expires_at IS NOT NULL AND v_coupon.expires_at < now() THEN
        RETURN;
    END IF;

    -- 4. Check global max uses
    IF v_coupon.max_uses IS NOT NULL AND v_coupon.used_count >= v_coupon.max_uses THEN
        RETURN;
    END IF;

    -- 5. Check minimum trip price
    IF v_coupon.min_trip_price IS NOT NULL AND p_trip_price < v_coupon.min_trip_price THEN
        RETURN;
    END IF;

    -- 6. Check budget exhaustion
    IF v_coupon.budget_limit IS NOT NULL AND v_coupon.spent_budget >= v_coupon.budget_limit THEN
        RETURN;
    END IF;

    -- 7. Check per-user usage limit
    IF v_coupon.max_uses_per_user IS NOT NULL THEN
        SELECT COUNT(*) INTO v_user_usage_count
        FROM coupon_usages cu
        JOIN user_coupons uc ON uc.id = cu.user_coupon_id
        WHERE uc.user_id = p_user_id
          AND uc.coupon_id = v_coupon.id;

        IF v_user_usage_count >= v_coupon.max_uses_per_user THEN
            RETURN;
        END IF;
    END IF;

    -- 8. Check first_ride_only
    IF v_coupon.first_ride_only = true THEN
        SELECT COUNT(*) INTO v_user_trip_count
        FROM trips t
        WHERE t.user_id = p_user_id
          AND t.status = 'completed';

        IF v_user_trip_count > 0 THEN
            RETURN;
        END IF;
    END IF;

    -- 9. Check new_users_only (account created within last 30 days)
    IF v_coupon.new_users_only = true THEN
        SELECT u.created_at INTO v_user_created_at
        FROM users u WHERE u.id = p_user_id;

        IF v_user_created_at IS NOT NULL AND v_user_created_at < (now() - interval '30 days') THEN
            RETURN;
        END IF;
    END IF;

    -- 10. Calculate discount
    IF v_coupon.discount_type = 'fixed' THEN
        v_discount := LEAST(v_coupon.discount_value, p_trip_price);
    ELSIF v_coupon.discount_type = 'percentage' THEN
        v_discount := ROUND(p_trip_price * v_coupon.discount_value / 100, 2);
        -- Apply max_discount cap
        IF v_coupon.max_discount IS NOT NULL THEN
            v_discount := LEAST(v_discount, v_coupon.max_discount);
        END IF;
        v_discount := LEAST(v_discount, p_trip_price);
    ELSE
        RETURN;
    END IF;

    -- 11. Cap discount against remaining budget
    IF v_coupon.budget_limit IS NOT NULL THEN
        v_discount := LEAST(v_discount, v_coupon.budget_limit - v_coupon.spent_budget);
    END IF;

    -- Ensure discount is positive
    IF v_discount <= 0 THEN
        RETURN;
    END IF;

    RETURN QUERY SELECT
        v_coupon.id,
        v_coupon.discount_type,
        v_coupon.discount_value,
        v_discount;
END;
$function$
", "language": "plpgsql", "arguments": "p_code character varying, p_trip_price numeric, p_user_id uuid", "truncated": false, "body_chars": 3493, "is_trigger": false, "return_type": "TABLE(id uuid, discount_type character varying, discount_value numeric, discount_amount numeric)", "is_trigger_function": false}

{"oid": "20895", "source": "CREATE OR REPLACE FUNCTION public.validate_trip_price(p_vehicle_type text, p_distance_km double precision, p_duration_min double precision)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_base_fare numeric;
    v_price_per_km numeric;
BEGIN
    SELECT base_fare, price_per_km
    INTO v_base_fare, v_price_per_km
    FROM vehicle_types
    WHERE name = p_vehicle_type
      AND is_active = true;

    RETURN FOUND;
END;
$function$
", "language": "plpgsql", "arguments": "p_vehicle_type text, p_distance_km double precision, p_duration_min double precision", "truncated": false, "body_chars": 493, "is_trigger": false, "return_type": "boolean", "is_trigger_function": false}

{"oid": "20897", "source": "CREATE OR REPLACE FUNCTION public.validate_trip_price_on_insert()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
    v_base_fare numeric;
    v_price_per_km numeric;
BEGIN
    SELECT base_fare, price_per_km
    INTO v_base_fare, v_price_per_km
    FROM vehicle_types
    WHERE name = NEW.vehicle_type
      AND is_active = true;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'Invalid vehicle type: %', NEW.vehicle_type
            USING ERRCODE = 'P0001';
    END IF;

    RETURN NEW;
END;
$function$
", "language": "plpgsql", "arguments": "", "truncated": false, "body_chars": 559, "is_trigger": true, "return_type": "trigger", "is_trigger_function": true}

{"oid": "20741", "source": "CREATE OR REPLACE FUNCTION public.validate_trip_status_transition()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE v_valid BOOLEAN := false;
BEGIN
  IF OLD.status = NEW.status THEN RETURN NEW; END IF;
  v_valid := (
    (OLD.status = 'searching' AND NEW.status IN ('accepted','cancelled')) OR
    (OLD.status = 'accepted'  AND NEW.status IN ('in_progress','cancelled')) OR
    (OLD.status = 'in_progress' AND NEW.status IN ('completed','cancelled')) OR
    (EXISTS (SELECT 1 FROM auth.users WHERE id = auth.uid() AND raw_app_meta_data->>'role' = 'admin'))
  );
  IF NOT v_valid THEN
    RAISE EXCEPTION 'Invalid trip status transition: % -> %', OLD.status, NEW.status;
  END IF;
  IF NEW.status = 'accepted' AND OLD.status != 'accepted' THEN NEW.accepted_at := COALESCE(NEW.accepted_at, NOW()); END IF;
  IF NEW.status = 'in_progress' AND OLD.status != 'in_progress' THEN NEW.started_at := COALESCE(NEW.started_at, NOW()); END IF;
  IF NEW.status = 'completed' AND OLD.status != 'completed' THEN NEW.completed_at := COALESCE(NEW.completed_at, NOW()); END IF;
  IF NEW.status = 'cancelled' AND OLD.status != 'cancelled' THEN NEW.cancelled_at := COALESCE(NEW.cancelled_at, NOW()); END IF;
  RETURN NEW;
END; $function$
", "language": "plpgsql", "arguments": "", "truncated": false, "body_chars": 1245, "is_trigger": true, "return_type": "trigger", "is_trigger_function": true}

{"oid": "25709", "source": "CREATE OR REPLACE FUNCTION public.validate_wallet_transaction_ref()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF NEW.wallet_type = 'driver' THEN
    IF NOT EXISTS (SELECT 1 FROM driver_wallets WHERE id = NEW.wallet_id) THEN
      RAISE EXCEPTION 'wallet_id % not found in driver_wallets', NEW.wallet_id;
    END IF;
  ELSIF NEW.wallet_type = 'user' THEN
    IF NOT EXISTS (SELECT 1 FROM user_wallets WHERE id = NEW.wallet_id) THEN
      RAISE EXCEPTION 'wallet_id % not found in user_wallets', NEW.wallet_id;
    END IF;
  ELSE
    RAISE EXCEPTION 'Invalid wallet_type: %', NEW.wallet_type;
  END IF;
  RETURN NEW;
END;
$function$
", "language": "plpgsql", "arguments": "", "truncated": false, "body_chars": 664, "is_trigger": true, "return_type": "trigger", "is_trigger_function": true}

{"oid": "19550", "source": "CREATE OR REPLACE FUNCTION public.verify_driver(p_driver_id uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF NOT is_admin_user() THEN
    RAISE EXCEPTION 'Only admins can verify drivers';
  END IF;

  UPDATE drivers_profile
  SET is_verified = true
  WHERE id = p_driver_id;

  PERFORM log_admin_action('VERIFY_DRIVER', 'drivers_profile', p_driver_id,
    jsonb_build_object('is_verified', false),
    jsonb_build_object('is_verified', true));

  RETURN FOUND;
END;
$function$
", "language": "plpgsql", "arguments": "p_driver_id uuid", "truncated": false, "body_chars": 512, "is_trigger": false, "return_type": "boolean", "is_trigger_function": false}
